+    @Test
+    public void testBitPatterns() {
+        LongConsumer test = p -> {
+            double value = Double.longBitsToDouble(p);
+            if (!Double.isFinite(value)) {
+                return;
+            }
+
+            assertRoundTrip(value);
+
+            double v = value;
+            for (int i = 0; i < 3; i++) {
+                v = Math.nextUp(v);
+                if (!Double.isFinite(v)) {
+                    break;
+                }
+
+                assertRoundTrip(v);
+            }
+
+            v = value;
+            for (int i = 0; i < 3; i++) {
+                v = Math.nextDown(v);
+                if (!Double.isFinite(v)) {
+                    break;
+                }
+
+                assertRoundTrip(v);
+            }
+        };
+
+        repeating(test);
+        walkingOnes(test);
+        walkingZeros(test);
+        slidingOnes(test);
+        slidingZeros(test);
+    }
+
+    private void walkingOnes(LongConsumer test) {
+        long v = 1L;
+        for (int i = 0; i < 64; i++) {
+            test.accept(v);
+            v <<= 1;
+        }
+    }
+
+    private void walkingZeros(LongConsumer test) {
+        long v = 0xffff_ffff_ffff_fffeL;
+        for (int i = 0; i < 64; i++) {
+            test.accept(v);
+            v <<= 1;
+            v |= 0x01L;
+        }
+    }
+
+    private void repeating(LongConsumer test) {
+        for (int i = 0; i < 256; i++) {
+            long v = i;
+            v = (v << 8) | i;
+            v = (v << 8) | i;
+            v = (v << 8) | i;
+            v = (v << 8) | i;
+            v = (v << 8) | i;
+            v = (v << 8) | i;
+            v = (v << 8) | i;
+            test.accept(v);
+        }
+    }
+
+    private void slidingOnes(LongConsumer test) {
+        for (int n = 1; n < 64; n++) {
+            long v = 0L;
+            for (int i = 0; i < n; i++) {
+                v = ((v << 1) | 0x1L);
+            }
+
+            for (int i = 0; i <= 64 - n; i++) {
+                long d = v << i;
+                test.accept(d);
+            }
+        }
+    }
+
+    private void slidingZeros(LongConsumer test) {
+        for (int n = 1; n < 64; n++) {
+            long v = 0L;
+            for (int i = 0; i < n; i++) {
+                v = ((v << 1) | 0x1L);
+            }
+
+            for (int i = 0; i <= 64 - n; i++) {
+                long d = ~(v << i);
+                test.accept(d);
+            }
+        }
+    }
